# values.yaml
service:
  type: ClusterIP  # override per env: NodePort | LoadBalancer
  port: 8080
  annotations: {}

# templates/service.yaml
apiVersion: v1
kind: Service
metadata:
  name: {{ include "mychart.fullname" . }}
  annotations: {{ toYaml .Values.service.annotations | nindent 4 }}
spec:
  type: {{ .Values.service.type }}
  ports:
    - port: {{ .Values.service.port }}
      targetPort: http
      {{- if eq .Values.service.type "NodePort" }}
      nodePort: 30080
      {{- end }}
  selector:
    {{- include "mychart.selectorLabels" . | nindent 4 }}

# values.yaml
startupProbe:
  httpGet:
    path: /healthz
    port: http
  failureThreshold: 30
  periodSeconds: 10

livenessProbe:
  httpGet:
    path: /healthz
    port: http
  periodSeconds: 15
  failureThreshold: 3

readinessProbe:
  httpGet:
    path: /ready
    port: http
  periodSeconds: 10
  failureThreshold: 3

# templates/deployment.yaml (inside containers block)
{{- with .Values.startupProbe }}
startupProbe: {{- toYaml . | nindent 12 }}
{{- end }}
{{- with .Values.livenessProbe }}
livenessProbe: {{- toYaml . | nindent 12 }}
{{- end }}
{{- with .Values.readinessProbe }}
readinessProbe: {{- toYaml . | nindent 12 }}
{{- end }}

# Layer environment-specific overrides at deploy time
helm upgrade --install my-app ./charts/my-app \
  -f values.yaml \
  -f values.staging.yaml \
  --set image.tag=$(git rev-parse --short HEAD) \
  --namespace staging --create-namespace

# _helpers.tpl — reusable label block
{{- define "my-app.labels" -}}
app.kubernetes.io/name: {{ include "my-app.name" . }}
app.kubernetes.io/instance: {{ .Release.Name }}
app.kubernetes.io/version: {{ .Chart.AppVersion | quote }}
{{- end }}

# Inspect release history and roll back if needed
helm history my-app --namespace staging
helm rollback my-app 3 --namespace staging

# Chart.yaml — KEDA as a dependency
dependencies:
  - name: keda
    version: "2.14.0"
    repository: "https://kedacore.github.io/charts"
    condition: keda.enabled

---
# templates/scaledobject.yaml
{{- if .Values.autoscaling.keda.enabled }}
apiVersion: keda.sh/v1alpha1
kind: ScaledObject
metadata:
  name: {{ include "mychart.fullname" . }}
spec:
  scaleTargetRef:
    name: {{ include "mychart.fullname" . }}
  minReplicaCount: {{ .Values.autoscaling.keda.minReplicas }}
  maxReplicaCount: {{ .Values.autoscaling.keda.maxReplicas }}
  triggers:
    - type: {{ .Values.autoscaling.keda.triggerType }}
      metadata: {{- toYaml .Values.autoscaling.keda.triggerMetadata | nindent 8 }}
{{- end }}
